sys_variable_value.value:
(function execute(inputs, outputs) {
  var enrollmentService = new EnrollmentService();
  var enrollment;

  try {
    enrollment = enrollmentService.createManualEnrollment(inputs.certificateRequestGr);
  } catch (error) {
  	if (error instanceof HttpError) {
      outputs.error_reason = error.reason;
    } else {
      outputs.error_reason = error.message;
    }

    return;
  }

  outputs.enrollment = enrollment;
})(inputs, outputs);

