sys_variable_value.value:
(function execute(inputs, outputs) {
	if (!inputs.errorReason) {
		var enrollmentService = new EnrollmentService();
      	enrollmentService.approveManualEnrollment(inputs.enrollment, inputs.certificateRequestGr.getValue("sys_id"));
	} 
})(inputs, outputs);

